class KongAdminClient:
    def __init__(self, admin_url: str, timeout: int = 15, headers: Optional[Dict[str, str]] = None):
        self.admin_url = admin_url.rstrip("/")
        self.timeout = timeout
        self.session = requests.Session()
        self.session.headers.update({"Content-Type": "application/json"})
        if headers:
            self.session.headers.update(headers)

    def _url(self, path: str) -> str:
        return f"{self.admin_url}/{path.lstrip('/')}"

    def _request(self, method: str, path: str, payload: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
        response = self.session.request(
            method=method.upper(),
            url=self._url(path),
            json=payload,
            timeout=self.timeout,
        )
        if not response.ok:
            raise RuntimeError(
                f"Kong Admin API request failed: {method.upper()} {self._url(path)} "
                f"status={response.status_code} body={response.text}"
            )
        if response.text.strip():
            return response.json()
        return {}

    def get(self, path: str) -> Dict[str, Any]:
        return self._request("GET", path)

    def post(self, path: str, payload: Dict[str, Any]) -> Dict[str, Any]:
        return self._request("POST", path, payload)

    def patch(self, path: str, payload: Dict[str, Any]) -> Dict[str, Any]:
        return self._request("PATCH", path, payload)

    def put(self, path: str, payload: Dict[str, Any]) -> Dict[str, Any]:
        return self._request("PUT", path, payload)

    def service_exists(self, name: str) -> bool:
        response = self.session.get(self._url(f"services/{name}"), timeout=self.timeout)
        return response.status_code == 200

    def route_exists(self, name: str) -> bool:
        response = self.session.get(self._url(f"routes/{name}"), timeout=self.timeout)
        return response.status_code == 200

    def upstream_exists(self, name: str) -> bool:
        response = self.session.get(self._url(f"upstreams/{name}"), timeout=self.timeout)
        return response.status_code == 200

    def target_exists(self, upstream_name: str, target: str) -> bool:
        response = self.session.get(self._url(f"upstreams/{upstream_name}/targets"), timeout=self.timeout)
        if response.status_code != 200:
            return False
        data = response.json().get("data", [])
        return any(item.get("target") == target for item in data)

    def create_or_update_service(self, service: Dict[str, Any]) -> Dict[str, Any]:
        name = service["name"]
        if self.service_exists(name):
            return self.patch(f"services/{name}", service)
        return self.post("services", service)

    def create_or_update_route(self, route: Dict[str, Any]) -> Dict[str, Any]:
        name = route["name"]
        if self.route_exists(name):
            return self.patch(f"routes/{name}", route)
        return self.post("routes", route)

    def create_or_update_upstream(self, upstream: Dict[str, Any]) -> Dict[str, Any]:
        name = upstream["name"]
        if self.upstream_exists(name):
            return self.patch(f"upstreams/{name}", upstream)
        return self.post("upstreams", upstream)

    def create_target(self, upstream_name: str, target: Dict[str, Any]) -> Dict[str, Any]:
        return self.post(f"upstreams/{upstream_name}/targets", target)

    def ensure_target(self, upstream_name: str, target: Dict[str, Any]) -> Dict[str, Any]:
        if self.target_exists(upstream_name, target["target"]):
            return {"status": "exists", "target": target["target"]}
        return self.create_target(upstream_name, target)


def configure_kong(client: KongAdminClient, config: Dict[str, Any]) -> Dict[str, Any]:
    results = {
        "upstreams": [],
        "targets": [],
        "services": [],
        "routes": [],
    }

    for upstream in config.get("upstreams", []):
        upstream_payload = {k: v for k, v in upstream.items() if k != "targets"}
        upstream_result = client.create_or_update_upstream(upstream_payload)
        results["upstreams"].append(upstream_result)

        for target in upstream.get("targets", []):
            target_result = client.ensure_target(upstream["name"], target)
            results["targets"].append(
                {
                    "upstream": upstream["name"],
                    "result": target_result,
                }
            )

    for service in config.get("services", []):
        service_result = client.create_or_update_service(service)
        results["services"].append(service_result)

    for route in config.get("routes", []):
        route_result = client.create_or_update_route(route)
        results["routes"].append(route_result)

    return results


