def load_config_from_file(path: str) -> Dict[str, Any]:
    with open(path, "r", encoding="utf-8") as f:
        return json.load(f)


def main() -> int:
    admin_url = os.getenv("KONG_ADMIN_URL", DEFAULT_ADMIN_URL)
    timeout = int(os.getenv("KONG_ADMIN_TIMEOUT", str(DEFAULT_TIMEOUT)))
    config_file = os.getenv("KONG_CONFIG_FILE")

    if len(sys.argv) > 1:
        config_file = sys.argv[1]

    if config_file:
        config = load_config_from_file(config_file)
    else:
        config = sample_config()

    client = KongAdminClient(admin_url=admin_url, timeout=timeout)

    try:
        result = configure_kong(client, config)
        print(json.dumps(result, indent=2))
        return 0
    except Exception as exc:
        print(json.dumps({"error": str(exc)}), file=sys.stderr)
        return 1


